import{c as r,Q as o,j as t,m as i}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"Blueprint First, Model Second: A Framework for Deterministic LLM Workflow","description":"","frontmatter":{"title":"Blueprint First, Model Second: A Framework for Deterministic LLM Workflow","arxiv_id":2508.02721,"authors":"Libin Qiu, Yuhang Ye, Zhirong Gao, Xide Zou, Junfu Chen, Ziming Gui, Weizhi Huang, Xiaobo Xue, Wenkai Qiu, Kun Zhao","published":"2025-08-01T00:00:00.000Z","source":"https://arxiv.org/abs/2508.02721","venue":"arXiv"},"headers":[],"relativePath":"research/agent-harness/references/2025-08-01-blueprint-first-model-second-2508.02721.md","filePath":"research/agent-harness/references/2025-08-01-blueprint-first-model-second-2508.02721.md","lastUpdated":1779901665000}'),n={name:"research/agent-harness/references/2025-08-01-blueprint-first-model-second-2508.02721.md"};function a(s,e,l,c,u,d){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="blueprint-first-model-second-a-framework-for-deterministic-llm-workflow" tabindex="-1">Blueprint First, Model Second: A Framework for Deterministic LLM Workflow <a class="header-anchor" href="#blueprint-first-model-second-a-framework-for-deterministic-llm-workflow" aria-label="Permalink to &quot;Blueprint First, Model Second: A Framework for Deterministic LLM Workflow&quot;">​</a></h1><p><strong>Authors</strong>: Libin Qiu, Yuhang Ye, Zhirong Gao, Xide Zou, Junfu Chen, Ziming Gui, Weizhi Huang, Xiaobo Xue, Wenkai Qiu, Kun Zhao</p><p><strong>Published</strong>: August 1, 2025</p><p><strong>Source</strong>: <a href="https://arxiv.org/abs/2508.02721" target="_blank" rel="noreferrer">https://arxiv.org/abs/2508.02721</a></p><p><strong>Subjects</strong>: Software Engineering (cs.SE); Artificial Intelligence (cs.AI); Programming Languages (cs.PL)</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>The paper addresses a key limitation in LLM agents: their inherent unpredictability makes them unsuitable for structured environments requiring reliable execution. The researchers introduce the Source Code Agent framework, which separates workflow logic from the generative model. Rather than allowing the LLM to determine operational paths, the framework codifies procedures into an &quot;Execution Blueprint&quot; executed deterministically, with the LLM relegated to handling &quot;bounded, complex sub-tasks within the workflow.&quot;</p><p>On the tau-bench benchmark, their approach achieved state-of-the-art results, &quot;outperforming the strongest baseline by 10.1 percentage points&quot; while improving efficiency. This work enables &quot;verifiable and reliable deployment of autonomous agents&quot; in procedurally governed applications.</p><hr><h2 id="core-innovation" tabindex="-1">Core Innovation <a class="header-anchor" href="#core-innovation" aria-label="Permalink to &quot;Core Innovation&quot;">​</a></h2><p>This research introduces the Source Code Agent framework, which addresses a fundamental limitation in current LLM-based systems: their inherent non-determinism. Rather than allowing language models to make all workflow decisions, the approach &quot;separates rigid, predefined process flow from flexible, model-driven execution of individual tasks.&quot;</p><hr><h2 id="key-architecture-components" tabindex="-1">Key Architecture Components <a class="header-anchor" href="#key-architecture-components" aria-label="Permalink to &quot;Key Architecture Components&quot;">​</a></h2><p>The framework consists of five integrated layers:</p><ol><li><strong>User-Defined Configuration</strong>: A visual interface where developers codify workflows as executable source code</li><li><strong>Componentized Agent SDK</strong>: Provides APIs for knowledge bases, LLM invocation, and custom tools</li><li><strong>Control Layer</strong>: Acts as the orchestration hub managing sessions and dialogue history</li><li><strong>Source Code Executor</strong>: Handles code scheduling, resource governance, and multi-language support</li><li><strong>Sandbox Runtime Environment</strong>: Provides secure, isolated execution with dependency management</li></ol><hr><h2 id="performance-results" tabindex="-1">Performance Results <a class="header-anchor" href="#performance-results" aria-label="Permalink to &quot;Performance Results&quot;">​</a></h2><p>Testing on the τ-bench benchmark (designed for complex user-tool-rule scenarios) demonstrated:</p><ul><li><strong>10.1 percentage point improvement</strong> over the strongest baseline on average Pass@1 scores</li><li><strong>66-82% reduction</strong> in tool calls across case studies</li><li>Consistent gains across airline and retail domains</li></ul><hr><h2 id="key-mechanisms" tabindex="-1">Key Mechanisms <a class="header-anchor" href="#key-mechanisms" aria-label="Permalink to &quot;Key Mechanisms&quot;">​</a></h2><p>The framework employs two critical validation techniques:</p><ol><li><strong>Double-Check (DC) Module</strong>: Programmatically re-introduces constraints at decision points, preventing errors from model drift</li><li><strong>Tool Consolidation</strong>: Encapsulates multi-step sequences into single high-level operations, reducing LLM cognitive load</li></ol><hr><h2 id="significance" tabindex="-1">Significance <a class="header-anchor" href="#significance" aria-label="Permalink to &quot;Significance&quot;">​</a></h2><p>This work represents a paradigm shift: transforming LLM agents from &quot;unpredictable exploration into a verifiable and auditable process,&quot; making them suitable for enterprise automation and safety-critical applications requiring procedural fidelity.</p>',27)])])}const g=r(n,[["render",a]]);export{m as __pageData,g as default};
